class ContextIntentAnalyzer {
private:
    std::vector<std::string> agenticKeywords = {
        "find and", "fix all", "generate", "create", "implement",
        "refactor", "optimize", "convert", "migrate", "add tests",
        "write documentation", "debug", "analyze"
    };
    
    std::vector<std::string> chatOnlyKeywords = {
        "explain", "what is", "how do", "why does", "help me understand",
        "just chat", "don't modify", "only talk", "no changes"
    };

public:
    UserIntent analyzeIntent(const std::string& userInput, 
                           const ConversationContext& context) {
        // Check for explicit preferences first
        if (containsChatOnlyDirective(userInput)) {
            return UserIntent::CHAT_ONLY;
        }
        
        // Analyze sentence structure and keywords
        if (isAgenticRequest(userInput)) {
            return UserIntent::AGENTIC_REQUEST;
        }
        
        // Check conversation history for patterns
        if (context.userPrefersChatOnly) {
            return UserIntent::CHAT_ONLY;
        }
        
        // Default to chat for ambiguous requests
        return UserIntent::CHAT_ONLY;
    }

private:
    bool containsChatOnlyDirective(const std::string& input) {
        return std::any_of(chatOnlyKeywords.begin(), chatOnlyKeywords.end(),
            [&input](const std::string& keyword) {
                return input.find(keyword) != std::string::npos;
            });
    }
    
    bool isAgenticRequest(const std::string& input) {
        // Look for action-oriented language
        return std::any_of(agenticKeywords.begin(), agenticKeywords.end(),
            [&input](const std::string& keyword) {
                return input.find(keyword) != std::string::npos;
            }) && 
        // And presence of code-related context
        (input.find("code") != std::string::npos ||
         input.find("file") != std::string::npos ||
         input.find("project") != std::string::npos);
    }
};
