2. Improved Implementation
cpp
Copy
class ContextIntentAnalyzer {
private:
    struct IntentPattern {
        std::vector<std::string> requiredWords;
        std::vector<std::string> forbiddenWords;
        std::vector<std::string> contextWords;
        UserIntent intent;
        double confidenceThreshold = 0.7;
    };

    std::vector<IntentPattern> patterns = {
        // Chat patterns
        {
            .requiredWords = {"explain", "what", "how"},
            .forbiddenWords = {"generate", "create", "write", "implement"},
            .contextWords = {"code", "function", "algorithm"},
            .intent = UserIntent::EXPLANATION
        },
        {
            .requiredWords = {"don't", "never", "no"},
            .forbiddenWords = {},
            .contextWords = {"modify", "change", "touch", "edit"},
            .intent = UserIntent::CHAT_ONLY
        },
        // Agentic patterns
        {
            .requiredWords = {"generate", "create", "write"},
            .forbiddenWords = {"explain", "how", "what"},
            .contextWords = {"function", "class", "file", "code"},
            .intent = UserIntent::CODE_GENERATION,
            .confidenceThreshold = 0.8
        }
    };

public:
    UserIntent analyzeIntent(const std::string& userInput, 
                           const ConversationContext& context) override {
        std::string lowerInput = toLower(userInput);
        
        // Check for explicit commands first
        if (lowerInput.starts_with("/chat")) return UserIntent::CHAT_ONLY;
        if (lowerInput.starts_with("/agentic")) return UserIntent::AGENTIC_REQUEST;
        
        // Analyze with patterns
        std::vector<std::pair<UserIntent, double>> scores;
        for (const auto& pattern : patterns) {
            double score = calculatePatternScore(lowerInput, pattern);
            if (score >= pattern.confidenceThreshold) {
                scores.push_back({pattern.intent, score});
            }
        }
        
        // Handle conflicts
        if (scores.empty()) {
            return context.userPrefersChatOnly ? UserIntent::CHAT_ONLY : UserIntent::CHAT_ONLY;
        }
        
        // Return highest confidence intent
        return std::max_element(scores.begin(), scores.end(),
            [](const auto& a, const auto& b) { return a.second < b.second; })->first;
    }

private:
    double calculatePatternScore(const std::string& input, const IntentPattern& pattern) {
        double score = 0.0;
        int matches = 0;
        
        // Check required words (must all be present)
        for (const auto& word : pattern.requiredWords) {
            if (input.find(word) != std::string::npos) {
                matches++;
            } else {
                return 0.0; // Required word missing
            }
        }
        
        // Check forbidden words (none should be present)
        for (const auto& word : pattern.forbiddenWords) {
            if (input.find(word) != std::string::npos) {
                return 0.0; // Forbidden word found
            }
        }
        
        // Check context words (increase confidence)
        for (const auto& word : pattern.contextWords) {
            if (input.find(word) != std::string::npos) {
                score += 0.3;
            }
        }
        
        return std::min(score, 1.0);
    }
};
