class ContextIntentAnalyzer {
public:
    UserIntent analyzeIntent(const std::string& userInput, 
                           const ConversationContext& context) override {
        // Learn from user corrections
        if (hasUserCorrectedSimilarRequest(userInput, context)) {
            return getCorrectedIntent(userInput, context);
        }
        
        // Check temporal patterns
        if (context.agenticActionsCount > 5 && context.chatOnlyRequestsCount == 0) {
            // User has been doing lots of agentic actions, maybe they want more
            if (isAmbiguous(userInput)) {
                return UserIntent::AGENTIC_REQUEST; // Default to agentic
            }
        }
        
        // Normal analysis
        return analyzeWithPatterns(userInput, context);
    }
    
private:
    bool hasUserCorrectedSimilarRequest(const std::string& input, 
                                      const ConversationContext& context) {
        for (const auto& [pattern, count] : context.userCorrections) {
            if (input.find(pattern) != std::string::npos && count > 2) {
                return true;
            }
        }
        return false;
    }
};
