Copy
// Add caching for repeated requests
class CachedIntentAnalyzer : public ContextIntentAnalyzer {
private:
    std::unordered_map<std::string, std::pair<UserIntent, std::chrono::time_point<>>> cache;
    std::chrono::minutes cacheDuration{5};
    
public:
    UserIntent analyzeIntent(const std::string& userInput, 
                           const ConversationContext& context) override {
        auto now = std::chrono::steady_clock::now();
        
        // Check cache
        if (auto it = cache.find(userInput); it != cache.end()) {
            if (now - it->second.second < cacheDuration) {
                return it->second.first;
            }
        }
        
        // Compute and cache
        UserIntent intent = ContextIntentAnalyzer::analyzeIntent(userInput, context);
        cache[userInput] = {intent, now};
        return intent;
    }
};
