// Memory/UserMemory.hpp
class UserMemory {
    sqlite3* db{};
public:
    UserMemory(const fs::path& file) { sqlite3_open(file.c_str(), &db); }
    ~UserMemory() { sqlite3_close(db); }

    template<typename T>
    void store(std::string_view key, const T& value) {
        std::string blob = jsonSerialize(value);
        sqlite3_exec(db,
            "INSERT OR REPLACE INTO facts(key,value) VALUES(?,?);",
            blob.c_str(), key.data());
    }

    template<typename T>
    std::optional<T> get(std::string_view key) {
        // single-row select into blob → jsonParse<T>
    }

    void recordCorrection(std::string_view pattern, UserIntent i) {
        sqlite3_exec(db,
            "INSERT INTO corrections(pattern,intent) VALUES(?,?)"
            "ON CONFLICT(pattern) DO UPDATE SET hits=hits+1;", pattern, int(i));
    }
};
