    void handleUserInput(const QString& raw) {
        ConversationContext ctx{
            .currentFile  = Editor::currentFile(),
            .selectedCode = Editor::selectedText(),
            .openFiles    = Editor::openTabs(),
            .history      = Chat::threadHistory(),
            .userPrefersChatOnly = userMem.get<bool>("prefers_chat").value_or(false)
        };

        UserIntent intent = intentAnalyzer.analyse(raw, ctx);
        if (intent == UserIntent::AGENTIC_REQUEST &&
            !userMem.get<bool>("auto_agentic").value_or(false)) {
            askPermission(raw);          // yes / no / always
            return;
        }

        // Build augmented prompt
        QString prompt = buildPrompt(raw, ctx);
        llama_client->chat(prompt, maxCtx);   // respects 4 k–1 M slider
    }

private:
    QString buildPrompt(const QString& user, const ConversationContext& ctx) {
        QString out;
        // 1. System card
        out += "You are RawrXD-Code, a helpful assistant.\n";
        // 2. Repo memory (if any)
        if (auto chunks = repoMem.retrieve(user, 3); !chunks.empty())
            out += "Relevant codebase context:\n" + join(chunks) + "\n";
        // 3. User memory
        if (auto style = userMem.get<QString>("coding_style"))
            out += "User prefers " + *style + " style.\n";
        // 4. Conversation history (capped to ctx window)
        out += ctx.history.join("\n") + "\n";
        // 5. Current request
        out += "User: " + user + "\nAssistant: ";
        return out;
    }
};
