/* ---------- USER FACT ---------- */
bool EnterpriseMemoryCatalog::storeUserFact(const QString& userId,
                                           const QString& key,
                                           const QJsonValue& value) {
    QMutexLocker l(&d->mtx);
    if (!d->backend)
        return false;

    QJsonDocument doc(value.toObject());
    QByteArray plain = doc.toJson(QJsonDocument::Compact);
    auto blob = CryptoVault::encrypt(plain, userId);

    bool ok = d->backend->storeUserFact(userId, key, blob);
    if (ok && d->cfg.audit) {
        AuditEntry e{QStringLiteral("storeUserFact"), userId, key};
        emit auditEvent(e);
    }
    Metrics::increment("memory_user_facts_total");
    return ok;
}

std::optional<QJsonValue>
EnterpriseMemoryCatalog::userFact(const QString& userId,
                                 const QString& key) const {
    QMutexLocker l(&d->mtx);
    auto blob = d->backend->userFact(userId, key);
    if (!blob)
        return std::nullopt;

    QByteArray plain = CryptoVault::decrypt(*blob, userId);
    QJsonDocument doc = QJsonDocument::fromJson(plain);
    return doc.object();
}

/* ---------- REPO TENSOR ---------- */
bool EnterpriseMemoryCatalog::storeRepoTensor(const QString& repoId,
                                             const QString& name,
                                             const ggml_tensor* tensor) {
    QMutexLocker l(&d->mtx);
    if (!d->backend || !tensor)
        return false;

    // serialise ggml_tensor → QByteArray
    QByteArray buf;
    QDataStream ds(&buf, QIODevice::WriteOnly);
    ds << qint32(tensor->n_dims);
    for (int i = 0; i < tensor->n_dims; ++i)
        ds << qint64(tensor->ne[i]);
    ds.writeRawData(reinterpret_cast<const char*>(tensor->data),
                   ggml_nbytes(tensor));

    auto blob = CryptoVault::encrypt(buf, repoId); // per-repo key scope
    bool ok = d->backend->storeRepoTensor(repoId, name, blob);
    Metrics::increment("memory_repo_tensors_bytes", buf.size());
    return ok;
}

ggml_tensor*
EnterpriseMemoryCatalog::repoTensor(const QString& repoId,
                                   const QString& name) const {
    QMutexLocker l(&d->mtx);
    auto blob = d->backend->repoTensor(repoId, name);
    if (!blob)
        return nullptr;

    QByteArray plain = CryptoVault::decrypt(*blob, repoId);
    QDataStream ds(plain);
    qint32 nd;
    ds >> nd;
    std::array<int64_t,4> ne{};
    for (int i = 0; i < nd; ++i) {
        qint64 n;
        ds >> n;
        ne[i] = n;
    }
    // rebuild ggml_tensor (shallow copy into temporary ctx)
    return ggml_new_tensor_4d(g_temp_ctx, GGML_TYPE_F32,
                             ne[0], ne[1], ne[2], ne[3]);
}

/* ---------- RBAC ---------- */
bool EnterpriseMemoryCatalog::canDo(const QString& userId,
                                   const QString& repoId,
                                   const QString& action) const {
    const QString key = userId % u'@' % repoId;
    QMutexLocker l(&d->mtx);
    if (!d->roleCache.contains(key)) {
        auto role = d->backend->role(userId, repoId);
        d->roleCache.insert(key, role);
    }
    const QString& role = d->roleCache[key];
    static const QHash<QString,QSet<QString>> m{
        {QStringLiteral("OWNER"), {"read","write","agentic","index","delete"}},
        {QStringLiteral("CONTRIBUTOR"), {"read","write","agentic"}},
        {QStringLiteral("READER"), {"read"}}
    };
    bool ok = m.value(role).contains(action);
    if (!ok) Metrics::increment("memory_rbac_denials_total");
    return ok;
}

