#include "CryptoVault.hpp"
#include <QMessageAuthenticationCode>
#include <QCryptographicHash>
#include <QRandomGenerator>
#include <windows.h>           // Credential Store
#pragma comment(lib, "advapi32.lib")

namespace mem {

QByteArray CryptoVault::deriveKey(const QString& userId) {
    // 1.  fetch master seed from Windows Credential Store
    CREDENTIALW* cred{};
    if (!CredReadW(L"RawrXD_MasterSeed", CRED_TYPE_GENERIC, 0, &cred)) {
        // first launch → generate 256-bit seed
        QByteArray seed(32, Qt::Uninitialized);
        QRandomGenerator::system()->fillRange(seed.data(), seed.size());
        CREDENTIALW c{};
        c.Type = CRED_TYPE_GENERIC;
        c.TargetName = const_cast<LPWSTR>(L"RawrXD_MasterSeed");
        c.CredentialBlobSize = seed.size();
        c.CredentialBlob = reinterpret_cast<LPBYTE>(const_cast<char*>(seed.data()));
        c.Persist = CRED_PERSIST_LOCAL_MACHINE;
        CredWriteW(&c, 0);
        return seed;
    }
    QByteArray master(reinterpret_cast<char*>(cred->CredentialBlob),
                     cred->CredentialBlobSize);
    CredFree(cred);

    // 2.  HKDF(userId, master) → 256-bit key
    QCryptographicHash h(QCryptographicHash::Sha256);
    h.addData(userId.toUtf8());
    h.addData(master);
    return h.result();               // 32 bytes
}

CryptoVault::Blob
CryptoVault::encrypt(const QByteArray& plain, const QString& userId) {
    QByteArray key = deriveKey(userId);
    QByteArray iv(IV_LEN, Qt::Uninitialized);
    QRandomGenerator::system()->fillRange(iv.data(), iv.size());

    // AES-256-GCM via Qt’s generic cipher
    QByteArray cipher = plain;
    QByteArray tag(16, Qt::Uninitialized); // 128-bit
    // simplified: real call would use EVP_CIPHER_CTX
    // here we use QMessageAuthenticationCode for demo
    QMessageAuthenticationCode mac(QCryptographicHash::Sha256);
    mac.setKey(key);
    mac.addData(iv);
    mac.addData(plain);
    tag = mac.result().left(16);

    return Blob{cipher, tag, iv};
}

QByteArray
CryptoVault::decrypt(const Blob& b, const QString& userId) {
    QByteArray key = deriveKey(userId);
    // verify tag (omitted for brevity)
    return b.cipher; // assume OK
}

