namespace mem {

/* ---------- SQLite BACKEND ---------- */
class SqliteBackend : public IBackend {
public:
    QSqlDatabase db;
    explicit SqliteBackend(const QString& path) {
        db = QSqlDatabase::addDatabase("QSQLITE", path);
        db.setDatabaseName(path);
        db.open();
    }
    void migrate() override {
        db.exec("CREATE TABLE IF NOT EXISTS user_fact(user TEXT, key TEXT, cipher BLOB, PRIMARY KEY(user,key));");
        db.exec("CREATE TABLE IF NOT EXISTS repo_tensor(repo TEXT, name TEXT, cipher BLOB, PRIMARY KEY(repo,name));");
        db.exec("CREATE TABLE IF NOT EXISTS user_role(user TEXT, repo TEXT, role TEXT, PRIMARY KEY(user,repo));");
    }
    bool storeUserFact(const QString& u, const QString& k, const CryptoVault::Blob& b) override {
        QSqlQuery q(db);
        q.prepare("INSERT OR REPLACE INTO user_fact VALUES(?,?,?);");
        q.addBindValue(u);
        q.addBindValue(k);
        q.addBindValue(b.cipher + b.tag + b.iv);
        return q.exec();
    }
    std::optional<CryptoVault::Blob>
    userFact(const QString& u, const QString& k) const override {
        QSqlQuery q(db);
        q.prepare("SELECT cipher FROM user_fact WHERE user=? AND key=?;");
        q.addBindValue(u);
        q.addBindValue(k);
        if (!q.exec() || !q.next()) return std::nullopt;
        QByteArray blob = q.value(0).toByteArray();
        CryptoVault::Blob b;
        int ctSize = blob.size() - 16 - 12;
        b.cipher = blob.left(ctSize);
        b.tag    = blob.mid(ctSize, 16);
        b.iv     = blob.right(12);
        return b;
    }
    QString role(const QString& u, const QString& r) const override {
        QSqlQuery q(db);
        q.prepare("SELECT role FROM user_role WHERE user=? AND repo=?;");
        q.addBindValue(u);
        q.addBindValue(r);
        if (q.exec() && q.next()) return q.value(0).toString();
        return QStringLiteral("READER"); // default
    }
};

/* ---------- Postgres BACKEND ---------- */
class PostgresBackend : public IBackend {
    QSqlDatabase pool[8];          // static pool, could be dynamic
public:
    explicit PostgresBackend(const QString& uri) {
        for (int i = 0; i < 8; ++i) {
            pool[i] = QSqlDatabase::addDatabase("QPSQL", QStringLiteral("pg%1").arg(i));
            pool[i].setConnectOptions(uri);
            pool[i].open();
        }
    }
    QSqlDatabase& pick() {         // round-robin
        static std::atomic<int> idx{0};
        return pool[(idx++) % 8];
    }
    void migrate() override {
        pick().exec("CREATE TABLE IF NOT EXISTS user_fact(user TEXT, key TEXT, cipher BYTEA, PRIMARY KEY(user,key));");
    }
    // … same CRUD as SqliteBackend but using pick() …
};

/* ---------- FACTORY ---------- */
BackendPtr makeBackend(const QString& uri) {
    if (uri.isEmpty()) {
        static QString fallback = QDir::temp().filePath("rawrxd_memory.db");
        return std::make_unique<SqliteBackend>(fallback);
    }
    return std::make_unique<PostgresBackend>(uri);
}

